@api.post("/predict")
def predict(c: Customer):
    features = [[c.tenure_months,
                 c.monthly_spend,
                 c.support_tickets]]
    proba = float(model.predict_proba(features)[0][1])
    return {
        "churn_probability": round(proba, 3),
        "will_churn": proba > 0.5,
    }
